+const std = @import("std");
+const llama = @import("llama.zig");
+const NGramCache = @import("ngram_cache.zig").NGramCache;
+const KVRingBuffer = @import("kv_ring_buffer.zig").KVRingBuffer;
+const AttentionTracker = @import("attention_tracker.zig").AttentionTracker;
+const MemoryMonitor = @import("memory_monitor.zig").MemoryMonitor;
+const LoraPool = @import("lora_pool.zig").LoraPool;
+
+/// TUI Dashboard for Zell "Brain Scan"
+///
+/// Provides real-time observability for the Zell inference engine:
+/// - Hippocampus state (Awake/Drowsy/Dreaming)
+/// - Fusion status (Base vs Fused model)
+/// - Speculation rate (N-gram hit rate)
+/// - Memory pressure (KV cache, pruning stats)
+///
+/// Uses ANSI escape codes for a lightweight, dependency-free TUI.
+pub const Dashboard = struct {
+    allocator: std.mem.Allocator,
+    writer: std.fs.File.Writer,
+
+    // Component references (optional, dashboard works with partial data)
+    ngram_cache: ?*NGramCache = null,
+    ring_buffer: ?*KVRingBuffer = null,
+    attention_tracker: ?*AttentionTracker = null,
+    memory_monitor: ?*MemoryMonitor = null,
+    lora_pool: ?*LoraPool = null,
+
+    // Hippocampus state tracking (atomic for thread safety)
+    hippocampus_state: std.atomic.Value(HippocampusState) = std.atomic.Value(HippocampusState).init(.awake),
+    fusion_version: std.atomic.Value(u32) = std.atomic.Value(u32).init(0),
+    fusion_ready: std.atomic.Value(bool) = std.atomic.Value(bool).init(false),
+
+    // Refresh configuration
+    refresh_interval_ms: u64 = 500,
+    last_refresh: i64 = 0,
+    enabled: bool = true,
+
+    // Dashboard dimensions
+    width: u32 = 65,
+
+    const Self = @This();
+
+    /// Hippocampus states for display
+    pub const HippocampusState = enum {
+        awake,
+        pre_drowsy,
+        drowsy,
+        dreaming,
+
+        pub fn toString(self: HippocampusState) []const u8 {
+            return switch (self) {
+                .awake => "Awake",
+                .pre_drowsy => "Pre-Drowsy",
+                .drowsy => "Drowsy",
+                .dreaming => "Dreaming",
+            };
+        }
+
+        pub fn toEmoji(self: HippocampusState) []const u8 {
+            return switch (self) {
+                .awake => "🧠",
+                .pre_drowsy => "😴",
+                .drowsy => "💤",
+                .dreaming => "🌙",
+            };
+        }
+    };
+
+    // =========================================================================
+    // ANSI Escape Sequences
+    // =========================================================================
+
+    const ESC = "\x1b";
+    const CLEAR_SCREEN = ESC ++ "[2J";
+    const CURSOR_HOME = ESC ++ "[H";
+    const HIDE_CURSOR = ESC ++ "[?25l";
+    const SHOW_CURSOR = ESC ++ "[?25h";
+    const CLEAR_LINE = ESC ++ "[2K";
+
+    pub const Color = enum {
+        reset,
+        red,
+        green,
+        yellow,
+        blue,
+        cyan,
+        magenta,
+        bold,
+        dim,
+
+        pub fn code(self: Color) []const u8 {
+            return switch (self) {
+                .reset => ESC ++ "[0m",
+                .red => ESC ++ "[31m",
+                .green => ESC ++ "[32m",
+                .yellow => ESC ++ "[33m",
+                .blue => ESC ++ "[34m",
+                .magenta => ESC ++ "[35m",
+                .cyan => ESC ++ "[36m",
+                .bold => ESC ++ "[1m",
+                .dim => ESC ++ "[2m",
+            };
+        }
+    };
+
+    // =========================================================================
+    // Initialization
+    // =========================================================================
+
+    pub fn init(allocator: std.mem.Allocator) Self {
+        return Self{
+            .allocator = allocator,
+            .writer = std.io.getStdErr().writer(),
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        // Show cursor on cleanup
+        self.writer.writeAll(SHOW_CURSOR) catch {};
+        _ = self;
+    }
+
+    // =========================================================================
+    // Component Attachment
+    // =========================================================================
+
+    pub fn attachNGramCache(self: *Self, cache: *NGramCache) void {
+        self.ngram_cache = cache;
+    }
+
+    pub fn attachRingBuffer(self: *Self, buffer: *KVRingBuffer) void {
+        self.ring_buffer = buffer;
+    }
+
+    pub fn attachAttentionTracker(self: *Self, tracker: *AttentionTracker) void {
+        self.attention_tracker = tracker;
+    }
+
+    pub fn attachMemoryMonitor(self: *Self, monitor: *MemoryMonitor) void {
+        self.memory_monitor = monitor;
+    }
+
+    pub fn attachLoraPool(self: *Self, pool: *LoraPool) void {
+        self.lora_pool = pool;
+    }
+
+    /// Update hippocampus state (called from hippocampus thread)
+    pub fn setHippocampusState(self: *Self, state: HippocampusState) void {
+        self.hippocampus_state.store(state, .release);
+    }
+
+    /// Update fusion status (called after weight fusion completes)
+    pub fn setFusionReady(self: *Self, version: u32) void {
+        self.fusion_version.store(version, .release);
+        self.fusion_ready.store(true, .release);
+    }
+
+    // =========================================================================
+    // Rendering
+    // =========================================================================
+
+    /// Render the full dashboard
+    pub fn render(self: *Self) !void {
+        if (!self.enabled) return;
+
+        // Hide cursor and move to home
+        try self.writer.writeAll(HIDE_CURSOR ++ CURSOR_HOME);
+
+        try self.renderHeader();
+        try self.renderModelStatus();
+        try self.renderSpeculation();
+        try self.renderMemory();
+        try self.renderFooter();
+
+        self.last_refresh = std.time.milliTimestamp();
+    }
+
+    /// Render only if refresh interval has passed
+    pub fn renderIfDue(self: *Self) !bool {
+        if (!self.enabled) return false;
+
+        const now = std.time.milliTimestamp();
+        if (now - self.last_refresh >= @as(i64, @intCast(self.refresh_interval_ms))) {
+            try self.render();
+            return true;
+        }
+        return false;
+    }
+
+    // =========================================================================
+    // Panel Rendering
+    // =========================================================================
+
+    fn renderHeader(self: *Self) !void {
+        const state = self.hippocampus_state.load(.acquire);
+
+        try self.drawBoxTop();
+        try self.writer.writeAll("│ ");
+        try self.setColor(.bold);
+        try self.writer.writeAll("ZELL BRAIN SCAN");
+        try self.setColor(.reset);
+
+        // Right-align state
+        const state_str = state.toString();
+        const emoji = state.toEmoji();
+        const padding = self.width - 17 - state_str.len - 4 - 2; // 17 = "ZELL BRAIN SCAN", 4 = emoji width estimate
+        try self.writer.writeByteNTimes(' ', padding);
+        try self.writer.print("[{s}] {s}", .{ state_str, emoji });
+        try self.writer.writeAll(" │\n");
+    }
+
+    fn renderModelStatus(self: *Self) !void {
+        try self.drawBoxSeparator();
+        try self.writer.writeAll("│ ");
+        try self.setColor(.cyan);
+        try self.writer.writeAll("MODEL");
+        try self.setColor(.reset);
+        try self.padToEnd(7);
+        try self.writer.writeAll("│\n");
+
+        // Fusion status
+        const fusion_ready = self.fusion_ready.load(.acquire);
+        const fusion_version = self.fusion_version.load(.acquire);
+
+        try self.writer.writeAll("│   Status: ");
+        if (fusion_ready) {
+            try self.setColor(.green);
+            try self.writer.print("Running on Fused (v{d})", .{fusion_version});
+            try self.setColor(.reset);
+        } else {
+            try self.setColor(.yellow);
+            try self.writer.writeAll("Running on Base Model");
+            try self.setColor(.reset);
+        }
+        try self.padToEnd(35 + if (fusion_ready) @as(usize, 3) else 0);
+        try self.writer.writeAll("│\n");
+
+        // LoRA adapter status
+        if (self.lora_pool) |pool| {
+            const stats = pool.getStats();
+            try self.writer.writeAll("│   Adapters: ");
+            try self.writer.print("{d} loaded ({d:.1} MB / {d:.1} MB)", .{
+                stats.loaded_count,
+                stats.total_memory_mb,
+                stats.max_memory_mb,
+            });
+            try self.padToEnd(50);
+            try self.writer.writeAll("│\n");
+        }
+    }
+
+    fn renderSpeculation(self: *Self) !void {
+        try self.drawBoxSeparator();
+        try self.writer.writeAll("│ ");
+        try self.setColor(.cyan);
+        try self.writer.writeAll("SPECULATION");
+        try self.setColor(.reset);
+        try self.padToEnd(13);
+        try self.writer.writeAll("│\n");
+
+        if (self.ngram_cache) |cache| {
+            const stats = cache.getStats();
+
+            // Hit rate with progress bar
+            try self.writer.writeAll("│   N-gram Hit Rate: ");
+            const hit_percent = @as(u32, @intFromFloat(stats.hit_rate * 100));
+            try self.progressBar(hit_percent, 100, 10);
+            try self.writer.print(" {d}%", .{hit_percent});
+            try self.padToEnd(42);
+            try self.writer.writeAll("│\n");
+
+            // Cache sizes
+            try self.writer.print("│   Trigrams: {d:>6} | Bigrams: {d:>6}", .{
+                stats.trigram_count,
+                stats.bigram_count,
+            });
+            try self.padToEnd(45);
+            try self.writer.writeAll("│\n");
+
+            // Hit/miss counts
+            try self.writer.print("│   Hits: {d:>8} | Misses: {d:>8}", .{
+                stats.cache_hits,
+                stats.cache_misses,
+            });
+            try self.padToEnd(45);
+            try self.writer.writeAll("│\n");
+        } else {
+            try self.writer.writeAll("│   ");
+            try self.setColor(.dim);
+            try self.writer.writeAll("N-gram cache not attached");
+            try self.setColor(.reset);
+            try self.padToEnd(30);
+            try self.writer.writeAll("│\n");
+        }
+    }
+
+    fn renderMemory(self: *Self) !void {
+        try self.drawBoxSeparator();
+        try self.writer.writeAll("│ ");
+        try self.setColor(.cyan);
+        try self.writer.writeAll("MEMORY");
+        try self.setColor(.reset);
+        try self.padToEnd(8);
+        try self.writer.writeAll("│\n");
+
+        // KV Ring Buffer stats
+        if (self.ring_buffer) |rb| {
+            const stats = rb.getStats();
+            const usage_percent = if (stats.effective_size > 0)
+                @as(u32, @intCast((stats.current_size * 100) / stats.effective_size))
+            else
+                0;
+
+            try self.writer.writeAll("│   KV Cache: ");
+            try self.progressBar(usage_percent, 100, 16);
+            try self.writer.print(" {d}/{d} ({d}%)", .{
+                stats.current_size,
+                stats.effective_size,
+                usage_percent,
+            });
+            try self.padToEnd(55);
+            try self.writer.writeAll("│\n");
+
+            try self.writer.print("│   Sinks: {d} [PROTECTED] | Window: {d}", .{
+                stats.sink_tokens,
+                stats.window_size,
+            });
+            try self.padToEnd(45);
+            try self.writer.writeAll("│\n");
+
+            try self.writer.print("│   Processed: {d} | Evictions: {d}", .{
+                stats.tokens_processed,
+                stats.evictions,
+            });
+            try self.padToEnd(45);
+            try self.writer.writeAll("│\n");
+        }
+
+        // Attention tracker stats
+        if (self.attention_tracker) |tracker| {
+            const stats = tracker.getStats();
+            const prune_percent = @as(u32, @intFromFloat(stats.prune_rate * 100));
+
+            try self.writer.print("│   Pruned: {d} tokens ({d}% rate)", .{
+                stats.tokens_pruned,
+                prune_percent,
+            });
+            try self.padToEnd(40);
+            try self.writer.writeAll("│\n");
+        }
+
+        // System memory
+        if (self.memory_monitor) |monitor| {
+            const stats = monitor.getStats();
+            const pressure_str = switch (stats.pressure) {
+                .low => "Low",
+                .medium => "Medium",
+                .high => "High",
+                .critical => "CRITICAL",
+            };
+            const pressure_color: Color = switch (stats.pressure) {
+                .low => .green,
+                .medium => .yellow,
+                .high => .red,
+                .critical => .red,
+            };
+
+            try self.writer.writeAll("│   System: ");
+            try self.progressBar(@as(u32, @intFromFloat(stats.usage_percent)), 100, 10);
+            try self.writer.print(" {d:.0}% (", .{stats.usage_percent});
+            try self.setColor(pressure_color);
+            try self.writer.print("{s}", .{pressure_str});
+            try self.setColor(.reset);
+            try self.writer.writeAll(")");
+            try self.padToEnd(45);
+            try self.writer.writeAll("│\n");
+        }
+    }
+
+    fn renderFooter(self: *Self) !void {
+        try self.drawBoxBottom();
+    }
+
+    // =========================================================================
+    // Drawing Helpers
+    // =========================================================================
+
+    fn drawBoxTop(self: *Self) !void {
+        try self.writer.writeAll("┌");
+        try self.writer.writeByteNTimes('-', self.width - 2);
+        try self.writer.writeAll("┐\n");
+    }
+
+    fn drawBoxSeparator(self: *Self) !void {
+        try self.writer.writeAll("├");
+        try self.writer.writeByteNTimes('-', self.width - 2);
+        try self.writer.writeAll("┤\n");
+    }
+
+    fn drawBoxBottom(self: *Self) !void {
+        try self.writer.writeAll("└");
+        try self.writer.writeByteNTimes('-', self.width - 2);
+        try self.writer.writeAll("┘\n");
+    }
+
+    fn padToEnd(self: *Self, current_len: usize) !void {
+        if (current_len < self.width - 2) {
+            try self.writer.writeByteNTimes(' ', self.width - 2 - current_len);
+        }
+    }
+
+    fn setColor(self: *Self, color: Color) !void {
+        try self.writer.writeAll(color.code());
+    }
+
+    fn progressBar(self: *Self, filled: u32, total: u32, width: u32) !void {
+        const ratio = if (total > 0)
+            @as(f32, @floatFromInt(filled)) / @as(f32, @floatFromInt(total))
+        else
+            0;
+        const filled_width = @as(u32, @intFromFloat(ratio * @as(f32, @floatFromInt(width))));
+
+        for (0..width) |i| {
+            if (i < filled_width) {
+                try self.writer.writeAll("█");
+            } else {
+                try self.writer.writeAll("░");
+            }
+        }
+    }
+
+    // =========================================================================
+    // Control
+    // =========================================================================
+
+    pub fn enable(self: *Self) void {
+        self.enabled = true;
+    }
+
+    pub fn disable(self: *Self) void {
+        self.enabled = false;
+        // Show cursor when disabled
+        self.writer.writeAll(SHOW_CURSOR) catch {};
+    }
+
+    pub fn toggle(self: *Self) void {
+        if (self.enabled) {
+            self.disable();
+        } else {
+            self.enable();
+        }
+    }
+
+    /// Clear the screen
+    pub fn clear(self: *Self) !void {
+        try self.writer.writeAll(CLEAR_SCREEN ++ CURSOR_HOME);
+    }
+};
+
+// =============================================================================
+// Compact Single-Line Status (Alternative to Full Dashboard)
+// =============================================================================
+
+/// Compact status line for non-TUI output
+/// Format: [State] Spec:78% KV:50% Mem:62% Pruned:3456
+pub fn formatStatusLine(
+    allocator: std.mem.Allocator,
+    state: Dashboard.HippocampusState,
+    ngram_cache: ?*NGramCache,
+    ring_buffer: ?*KVRingBuffer,
+    attention_tracker: ?*AttentionTracker,
+    memory_monitor: ?*MemoryMonitor,
+) ![]u8 {
+    var buf = std.ArrayList(u8).init(allocator);
+    errdefer buf.deinit();
+
+    const writer = buf.writer();
+
+    // State
+    try writer.print("[{s}]", .{state.toString()});
+
+    // Speculation
+    if (ngram_cache) |cache| {
+        const stats = cache.getStats();
+        try writer.print(" Spec:{d:.0}%", .{stats.hit_rate * 100});
+    }
+
+    // KV Cache
+    if (ring_buffer) |rb| {
+        const stats = rb.getStats();
+        const usage = if (stats.effective_size > 0)
+            @as(f32, @floatFromInt(stats.current_size)) / @as(f32, @floatFromInt(stats.effective_size)) * 100
+        else
+            0;
+        try writer.print(" KV:{d:.0}%", .{usage});
+    }
+
+    // Memory
+    if (memory_monitor) |monitor| {
+        const stats = monitor.getStats();
+        try writer.print(" Mem:{d:.0}%", .{stats.usage_percent});
+    }
+
+    // Pruning
+    if (attention_tracker) |tracker| {
+        const stats = tracker.getStats();
+        try writer.print(" Pruned:{d}", .{stats.tokens_pruned});
+    }
+
+    return buf.toOwnedSlice();
+}
