+
+    try std.testing.expect(dashboard.enabled);
+    try std.testing.expectEqual(@as(u64, 500), dashboard.refresh_interval_ms);
+}
+
+test "dashboard state updates" {
+    const allocator = std.testing.allocator;
+
+    var dashboard = Dashboard.init(allocator);
+    defer dashboard.deinit();
+
+    // Initial state should be awake
+    try std.testing.expectEqual(Dashboard.HippocampusState.awake, dashboard.hippocampus_state.load(.acquire));
+
+    // Update state
+    dashboard.setHippocampusState(.dreaming);
+    try std.testing.expectEqual(Dashboard.HippocampusState.dreaming, dashboard.hippocampus_state.load(.acquire));
+
+    // Update fusion
+    dashboard.setFusionReady(3);
+    try std.testing.expect(dashboard.fusion_ready.load(.acquire));
+    try std.testing.expectEqual(@as(u32, 3), dashboard.fusion_version.load(.acquire));
+}
+
+test "hippocampus state strings" {
